# --- compact_closed ---


def test_compact_closed_basic():
    pr = {
        "number": 20,
        "title": "superseded by #21",
        "author": {"login": "dev"},
        "createdAt": "2026-04-01T10:00:00Z",
        "closedAt": "2026-04-03T10:00:00Z",
        "additions": 200,
        "deletions": 100,
    }
    result = compact_closed(pr, "org/repo")
    assert result["r"] == "org/repo"
    assert result["n"] == 20
    assert result["a"] == "dev"
    assert result["l"] == 300
    assert result["x"] == "2026-04-03"
    assert result["c"] == "2026-04-01"
